const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const redis = require('redis');
const { promisify } = require('util');

const app = express();
const client = redis.createClient();

const PORT = 3000;
const ACCESS_TOKEN_SECRET = 'your_access_token_secret';
const REFRESH_TOKEN_SECRET = 'your_refresh_token_secret';
const ACCESS_TOKEN_EXPIRATION = '15m';
const REFRESH_TOKEN_EXPIRATION = 365 * 24 * 60 * 60; // 1 year in seconds

const setAsync = promisify(client.set).bind(client);
const getAsync = promisify(client.get).bind(client);

app.use(bodyParser.json());

function generateAccessToken(user) {
  return jwt.sign(user, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRATION });
}

function generateRefreshToken(user) {
  const refreshToken = crypto.randomBytes(64).toString('hex');
  const payload = { ...user, token: refreshToken };
  return jwt.sign(payload, REFRESH_TOKEN_SECRET, { expiresIn: REFRESH_TOKEN_EXPIRATION });
}

app.post('/token', async (req, res) => {
  const { username, password } = req.body;
  if (username !== 'user' || password !== 'pass') {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const user = { username };
  const accessToken = generateAccessToken(user);
  const refreshToken = generateRefreshToken(user);

  await setAsync(refreshToken, JSON.stringify(user), 'EX', REFRESH_TOKEN_EXPIRATION);

  res.json({ accessToken, refreshToken });
});

app.post('/token/refresh', async (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) {
    return res.status(401).json({ error: 'Refresh token required' });
  }

  try {
    const decoded = jwt.verify(refreshToken, REFRESH_TOKEN_SECRET);
    const storedUser = await getAsync(refreshToken);

    if (!storedUser || JSON.stringify(decoded) !== storedUser) {
      return res.status(403).json({ error: 'Invalid refresh token' });
    }

    const user = { username: decoded.username };
    const accessToken = generateAccessToken(user);

    res.json({ accessToken });
  } catch (err) {
    res.status(403).json({ error: 'Invalid refresh token' });
  }
});

app.listen(PORT, () => {
  console.log(`Authorization server running on http://localhost:${PORT}`);
});